const body = $input.first().json.body || $input.first().json;

// Required fields
if (!body.contact_name) throw new Error('contact_name is required');
if (!body.meeting_date) throw new Error('meeting_date is required');

// Parse and format date
const meetingDate = new Date(body.meeting_date);
body.meeting_date_formatted = meetingDate.toLocaleDateString('pt-PT', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

// Set 24h before reminder
body.reminder_at = new Date(meetingDate.getTime() - 24 * 60 * 60 * 1000).toISOString();
body.meeting_type = body.meeting_type || 'vendedor';

return [{ json: body }];

